memberdef.initializer:
if (kv_max(*line_buf) == 0) { \
  kv_resize(*line_buf, LINE_BUFFER_MIN_SIZE); \
} \
if (c == NL) { \
  kv_push(*line_buf, NUL); \
  if (to_err) { \
    emsg(line_buf->items); \
  } else { \
    msg(line_buf->items, 0); \
  } \
  if (msg_silent == 0) { \
    msg_didout = true; \
  } \
  kv_drop(*line_buf, kv_size(*line_buf)); \
  kv_resize(*line_buf, LINE_BUFFER_MIN_SIZE); \
} else if (c == NUL) { \
  kv_push(*line_buf, NL); \
} else { \
  kv_push(*line_buf, c); \
}
